# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import play.api.libs.Files
import java.nio.file.{Path, Paths, Files => JFiles}
import scala.io.Source
import scala.util.{Try, Using, Success, Failure}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsBaseDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  /**
   * Serves a file from the uploads directory.
   * Supports subdirectories, e.g., /files/images/photo.png
   * Includes path traversal protection.
   */
  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>

    // Resolve the requested path and normalize it to remove any ../ sequences
    val requestedPath: Path = uploadsBaseDir.resolve(filename).toAbsolutePath.normalize()

    // Security check: ensure the resolved path is still within the uploads directory
    if (!requestedPath.startsWith(uploadsBaseDir)) {
      Forbidden("Access denied: path traversal detected")
    } else if (!JFiles.exists(requestedPath)) {
      NotFound(s"File not found")
    } else if (!JFiles.isRegularFile(requestedPath)) {
      BadRequest("Requested path is not a regular file")
    } else if (!JFiles.isReadable(requestedPath)) {
      Forbidden("File is not readable")
    } else {
      // Validate filename characters - reject suspicious input
      val allowedPattern = "^[a-zA-Z0-9._\\-/]+$".r
      filename match {
        case allowedPattern() =>
          // Determine content type based on file extension
          val contentType = detectContentType(requestedPath.getFileName.toString)

          // Use sendPath for efficient binary-safe file serving
          Ok.sendPath(requestedPath, inline = true).as(contentType)

        case _ =>
          BadRequest("Invalid filename: contains disallowed characters")
      }
    }
  }

  /**
   * Lists files in a subdirectory of uploads.
   */
  def listFiles(subdirectory: Option[String]): Action[AnyContent] = Action { implicit request =>
    val targetDir = subdirectory match {
      case Some(sub) => uploadsBaseDir.resolve(sub).toAbsolutePath.normalize()
      case None => uploadsBaseDir
    }

    if (!targetDir.startsWith(uploadsBaseDir)) {
      Forbidden("Access denied: path traversal detected")
    } else if (!JFiles.exists(targetDir) || !JFiles.isDirectory(targetDir)) {
      NotFound("Directory not found")
    } else {
      import scala.jdk.CollectionConverters._
      val files = JFiles.list(targetDir).iterator().asScala.toList.map { path =>
        val isDir = JFiles.isDirectory(path)
        Map(
          "name" -> path.getFileName.toString,
          "type" -> (if (isDir) "directory" else "file"),
          "size" -> (if (isDir) "0" else JFiles.size(path).toString)
        )
      }
      Ok(play.api.libs.json.Json.toJson(files))
    }
  }

  private def detectContentType(filename: String): String = {
    val extension = filename.toLowerCase.split('.').lastOption.getOrElse("")
    extension match {
      case "html" | "htm" => "text/html"
      case "css"          => "text/css"
      case "js"           => "application/javascript"
      case "json"         => "application/json"
      case "xml"          => "application/xml"
      case "txt"          => "text/plain"
      case "csv"          => "text/csv"
      case "pdf"          => "application/pdf"
      case "png"          => "image/png"
      case "jpg" | "jpeg" => "image/jpeg"
      case "gif"          => "image/gif"
      case "svg"          => "image/svg+xml"
      case "zip"          => "application/zip"
      case "gz"           => "application/gzip"
      case _              => "application/octet-stream"
    }
  }
}